class PlayDisc {
    constructor(game, bga) {
        this.game = game;
        this.bga = bga;
    }

    onEnteringState(args, isCurrentPlayerActive) {
        this.bga.statusBar.setTitle(isCurrentPlayerActive ? 
            _('${you} must play a disc') :
            _('${actplayer} must play a disc')
        );

        if (isCurrentPlayerActive) {            
            this.updatePossibleMoves(args.possibleMoves);
        }
    }
}

updatePossibleMoves(possibleMoves) {
    // Remove current possible moves
    document.querySelectorAll('.selectable').forEach(div => div.classList.remove('selectable'));

    for( let x in possibleMoves ) {
        for( let y in possibleMoves[ x ] ) {
            // x,y is a possible move
            document.getElementById(`square_${x}_${y}`).classList.add('selectable');
        }            
    }

    this.bga.gameui.addTooltipToClass( 'selectable', '', _('Place a disc here') );
}

.square.selectable {
    background-color: color-mix(in srgb, darkgreen, white 50%);
    cursor: pointer;
}

onPlayDisc(x, y) {
        // The click does nothing when not active
        if (!this.bga.players.isCurrentPlayerActive()) {
            return;
        }

        if(!document.getElementById(`square_${x}_${y}`).classList.contains('selectable')) {
            // This is not a possible move => the click does nothing
            return;
        }

    this.bga.actions.performAction("actPlayDisc", {
        x:x,
        y:y,
    });
}

#[PossibleAction]
function actPlayDisc( int $x, int $y, int $activePlayerId )
{

// Now, check if this is a possible move
$board = $this->game->boardManager->getBoard();
$turnedOverDiscs = $this->game->boardManager->getTurnedOverDiscs( $x, $y, $activePlayerId, $board );

if( count( $turnedOverDiscs ) === 0 ) {
    throw new SystemException("Impossible move");
}

public function applyMove(int $playerId, int $x, int $y, array $turnedOverDiscs): void
{
    $positions = [];
    foreach ($turnedOverDiscs as $turnedOver) {
        $turnedX = (int) $turnedOver['x'];
        $turnedY = (int) $turnedOver['y'];
        $positions[] = "($turnedX,$turnedY)";
    }
    $positions[] = "($x,$y)";

    $sql = "UPDATE `board` SET `board_player` = $playerId WHERE (`board_x`, `board_y`) IN (" . implode(',', $positions) . ")";
    $this->game->DbQuery($sql);
}

